    >>> _calc_percentages_if_missing(["H123", "H234", "H345"], "split_equally")
    {"H123": 33.33, "H234": 33.33, "H345": 33.33}
    >>> _calc_percentages_if_missing(["H123", "H234", "H345"], "select_first")
    {"H123": 100}

